function nudgeCombatSpawn(x,y,r=19){let px=x,py=y;if(!terrainBlockedAt(px,py,r))return{x:px,y:py};for(let rad=28;rad<=260;rad+=28){for(let i=0;i<18;i++){let a=i/18*Math.PI*2,nx=px+Math.cos(a)*rad,ny=py+Math.sin(a)*rad;nx=Math.max(24,Math.min(WORLD_W-24,nx));ny=Math.max(62,Math.min(WORLD_H-24,ny));if(!terrainBlockedAt(nx,ny,r))return{x:nx,y:ny}}}return{x:px,y:py}}function liveCombatWorld(){try{let pack=(window.MapLivePack&&typeof MapLivePack.read==='function'?MapLivePack.read():null);if(!pack||!pack.worlds)return null;let mid=S&&S.mapId,worlds=Object.values(pack.worlds),active=pack.activeWorldId&&pack.worlds[pack.activeWorldId];function isCombat(w){if(!w||w.kind==='town')return false;if(w.kind==='combat')return true;if(w.mapId&&['chaos','ruins','frost'].includes(w.mapId))return true;if(/^builtin-(chaos|ruins|frost)$/.test(String(w.id||'')))return true;return false}function match(w){if(!isCombat(w))return false;if(w.mapId&&w.mapId===mid)return true;if(w.id==='builtin-'+mid)return true;if(!w.mapId&&String(w.id||'').includes(String(mid||'')))return true;return false}let cands=worlds.filter(match);if(active&&match(active))return active;if(cands.length){cands.sort((a,b)=>String(b.updatedAt||'').localeCompare(String(a.updatedAt||'')));return cands[0]}if(active&&isCombat(active)&&(!active.mapId||active.mapId===mid))return active;return pack.worlds['builtin-'+mid]||null}catch(_){return null}}
function terrainSeed(){try{let live=liveCombatWorld();if(live&&Array.isArray(live.entities)){let out=live.entities.filter(e=>e&&e.enabled!==false&&String(e.kind||'').startsWith('terrain-')).map(e=>{let type=(e.meta&&e.meta.terrainType)||String(e.kind).replace(/^terrain-/,''),sc=Number(e.scale)||1,r=Number(e.meta&&e.meta.r);if(!(r>0))r=Math.max(20,(Math.max((e.w||0)*sc,(e.h||0)*sc)/2.15));let solid;if(e.meta&&typeof e.meta.solid==='boolean')solid=!!e.meta.solid;else if(type==='icefield')solid=false;else solid=!!(e.collision&&(e.collision.mode==='circle'||e.collision.mode==='polygon'));let poly=null;if(e.collision&&e.collision.mode==='polygon'&&e.collision.points&&e.collision.points.length>=3){poly=(e.collision.space==='world')?e.collision.points:e.collision.points.map(p=>[e.x+(p[0]||0),e.y+(p[1]||0)])};let rot=Number(e.rotation)||0;return{x:e.x,y:e.y,r,type,solid,poly,rotation:rot,flipX:!!e.flipX,flipY:!!e.flipY,a:rot*Math.PI/180,s:1}});if(live.collisions&&live.collisions.length){for(const z of live.collisions){if(z&&z.mode==='polygon'&&z.points&&z.points.length>=3)out.push({x:z.points[0][0],y:z.points[0][1],r:40,type:'block',solid:true,poly:z.points,a:0,s:1})}}return out}}catch(_){}let map=S.mapId,defs={chaos:[['rift',46,0],['rune',34,0],['obelisk',16,1]],ruins:[['crack',42,0],['pillar',14,1],['wall',10,1],['altar',7,1]],frost:[['snow',44,0],['icecrack',30,0],['crystal',11,1],['icefield',8,0]]}[map]||[];let out=[],cx=WORLD_W/2,cy=WORLD_H/2;for(const [type,count,solid] of defs)for(let i=0;i<count;i++){let r=type==='icefield'?rand(95,155):solid?rand(34,62):rand(28,86),ok=false,x=0,y=0;for(let t=0;t<60&&!ok;t++){x=rand(140,WORLD_W-140);y=rand(160,WORLD_H-160);ok=Math.hypot(x-cx,y-cy)>520&&out.every(o=>Math.hypot(x-o.x,y-o.y)>r+o.r+(solid||o.solid?90:28))}if(ok)out.push({x,y,r,type,solid:!!solid,a:rand(0,TAU),s:rand(.75,1.25)})}return out}
