function frameOf(t,fps=7){return Math.floor(t*fps)%4}function drawSheet(img,x,y,size,frame,rot=0,sx=1,sy=1,a=1){if(!img?.complete){ctx.fillStyle='#fff';ctx.fillRect(x-size/2,y-size/2,size,size);return}const fw=img.width/2,fh=img.height/2;ctx.save();ctx.globalAlpha=a;ctx.translate(x,y);ctx.rotate(rot);ctx.scale(sx,sy);ctx.drawImage(img,frame%2*fw,Math.floor(frame/2)*fh,fw,fh,-size/2,-size/2,size,size);ctx.restore()}function drawGrid(img,x,y,size,i,cols,rows,a=1,rot=0){if(!img?.complete)return;let fw=img.width/cols,fh=img.height/rows,ratio=fh/fw,w=size,h=size*ratio;ctx.save();ctx.globalAlpha=a;ctx.translate(x,y);ctx.rotate(rot);ctx.drawImage(img,i%cols*fw,Math.floor(i/cols)*fh,fw,fh,-w/2,-h/2,w,h);ctx.restore()}function drawAction(img,x,y,size,row,frame,a=1,sx=1){if(!img?.complete)return drawSheet(img,x,y,size,0,0,sx,1,a);let cols=6,rows=4,fw=img.width/cols,fh=img.height/rows,ratio=fh/fw,w=size,h=size*ratio;ctx.save();ctx.globalAlpha=a;ctx.translate(x,y);ctx.scale(sx,1);ctx.drawImage(img,(frame%cols)*fw,row*fh,fw,fh,-w/2,-h/2,w,h);ctx.restore()}function artDef(id){return ARTIFACTS.find(a=>a[0]===id)}function artIndex(id){return ARTIFACTS.findIndex(a=>a[0]===id)}function artIcon(i){return `<span class="iconSprite" style="background-position:${(i%5)*25}% ${Math.floor(i/5)*100}%"></span>`}function nearest(list,p){let best=null,bd=1e9;for(const it of list){let d=dist(it,p);if(d<bd){bd=d;best=it}}return best}function threatScore(e){let v={healer:130,eye:105,wraith:100,guardian:82,shield:78,charger:64,skeleton:28,slime:24,imp:18}[e.type]||30;if(e.elite)v+=35;if(e.shield>0)v+=18;if(e.hp/e.max<.28)v+=16;if(e.boss)v+=999;return v}function targetEnemy(p){let boss=nearest(S.enemies.filter(e=>e.boss),p);if(boss)return boss;let pool=S.enemies.filter(e=>dist(e,p)<520);if(!pool.length)return nearest(S.enemies,p);return pool.sort((a,b)=>threatScore(b)-threatScore(a)||dist(a,p)-dist(b,p))[0]}
